//! telemetry-frame — Converts Mesh Carrier Assessment JSON into a PleromaticFrame (bincode).
//!
//! Usage: telemetry-frame --json <B64_JSON> --output fingerprint.frame

use base64::{engine::general_purpose::STANDARD as BASE64_STANDARD, Engine as _};
use distributed_inference::acoustic::PersistenceBarcode;
use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use serde_json::Value;
use std::env;
use std::fs::File;
use std::io::Write;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().collect();
    let mut json_b64 = None;
    let mut semantic_text = None;
    let mut output_path = "fingerprint.frame".to_string();

    for i in 0..args.len() {
        if args[i] == "--json" && i + 1 < args.len() {
            json_b64 = Some(&args[i + 1]);
        } else if args[i] == "--semantic" && i + 1 < args.len() {
            semantic_text = Some(&args[i + 1]);
        } else if args[i] == "--output" && i + 1 < args.len() {
            output_path = args[i + 1].clone();
        }
    }

    if let Some(text) = semantic_text {
        let frame = PleromaticFrame::grounding(
            "iot_snatcher".to_string(),
            PleromaticMediaType::Semantic,
            text.as_bytes().to_vec(),
        );
        let bytes = bincode::serialize(&frame)?;
        File::create(Path::new(&output_path))?.write_all(&bytes)?;
        return Ok(());
    }

    let b64 = json_b64.ok_or("Missing --json <BASE64> or --semantic <TEXT>")?;
    let json_bytes = BASE64_STANDARD.decode(b64)?;
    let v: Value = serde_json::from_slice(&json_bytes)?;

    // Extract metrics for the barcode
    let beta1 = v["spectral"]["fingerprintBuley"]["beta1"]
        .as_u64()
        .unwrap_or(1) as u32;
    let dilation = v["spectral"]["fingerprintBuley"]["dilation"]
        .as_f64()
        .unwrap_or(1.0) as f32;
    let density = v["spectral"]["fingerprintBuley"]["density"]
        .as_f64()
        .unwrap_or(1.0) as f32;
    let lifespan = v["spectral"]["fingerprintBuley"]["lifespan"]
        .as_u64()
        .unwrap_or(1) as u32;

    // Extract MonsterPath (represented as tokens in JSON if possible, or parsed from fingerprint string)
    // For now, we'll try to find a "monsterPath" array or fallback to a mock one if only string exists.
    // (Actual host implementation should be updated to include full path in assessment).

    // Fallback MonsterPath logic
    let mut tokens = vec![
        distributed_inference::pleromatic_frame::SignalToken::T,
        distributed_inference::pleromatic_frame::SignalToken::S,
        distributed_inference::pleromatic_frame::SignalToken::V,
    ];

    if let Some(path_str) = v["spectral"]["fingerprint"].as_str() {
        // Simple parser for [T, F, ...] string format
        tokens.clear();
        for part in path_str.split(',').map(|s| s.trim()) {
            let clean = part.trim_start_matches('[').trim_end_matches(']');
            if clean.is_empty() {
                continue;
            }
            if clean.starts_with('T') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::T);
            } else if clean.starts_with('F') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::F { r: 0 });
            } else if clean.starts_with('R') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::R { r: 0 });
            } else if clean.starts_with('L') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::L);
            } else if clean.starts_with('S') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::S);
            } else if clean.starts_with('W') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::W { m: 0 });
            } else if clean.starts_with('V') {
                tokens.push(distributed_inference::pleromatic_frame::SignalToken::V);
            }
        }
    }

    let data = bincode::serialize(&tokens)?;

    let mut frame = PleromaticFrame::grounding(
        v["spectral"]["traceCompact"]["requestId"]
            .as_str()
            .unwrap_or("edge_trace")
            .to_string(),
        PleromaticMediaType::Fingerprint,
        data,
    );

    frame.barcode = PersistenceBarcode {
        beta1,
        lifespan,
        dilation,
        density,
    };

    frame.seq = v["spectral"]["traceCompact"]["sequenceLength"]
        .as_u64()
        .unwrap_or(0);

    let bytes = bincode::serialize(&frame)?;
    let mut f = File::create(Path::new(&output_path))?;
    f.write_all(&bytes)?;

    println!(
        " [ TELEMETRY BRIDGE: INGESTED CERTIFICATE -> {} ] ",
        output_path
    );

    Ok(())
}
